import React from "https://esm.sh/react@18.2.0";
import ReactDOM from "https://esm.sh/react-dom@18.2.0";

function formatDate(dateStr) {
  if (!dateStr) return "N/A";
  const d = new Date(dateStr);
  return d.toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' });
}

function App() {
  const [model, setModel] = React.useState(appsmith.model);

  React.useEffect(() => {
    appsmith.onModelChange((newModel) => {
      setModel({ ...newModel });
    });
  }, []);

  const dialRef = model.dial_ref;
  const dialExpiry = model.dial_expiry;
  const msaSigned = model.msa_signed;

  const now = new Date();
  now.setHours(0,0,0,0);
  const expiry = dialExpiry ? new Date(dialExpiry) : null;
  const isExpired = expiry && expiry < now;
  const msaOk = msaSigned === 'Yes' || msaSigned === true || msaSigned === 'true';

  const badgeStyle = (bg, color) => ({
    display: 'inline-flex', alignItems: 'center', gap: '5px', padding: '4px 10px',
    borderRadius: '20px', fontSize: '12px', fontWeight: 500, background: bg, color: color
  });

  const tileStyle = (warn) => ({
    background: warn ? '#FCEBEB' : '#f9fafb',
    border: warn ? '0.5px solid #F09595' : '0.5px solid transparent',
    borderRadius: '6px', padding: '10px 12px'
  });

  const labelStyle = (warn) => ({
    fontSize: '11px', color: warn ? '#A32D2D' : '#9ca3af', textTransform: 'uppercase', marginBottom: '5px'
  });

  return (
    <div style={{ fontFamily: 'sans-serif' }}>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '12px' }}>

        <div style={tileStyle(isExpired)}>
          <div style={labelStyle(isExpired)}>Dial ref</div>
          <span style={badgeStyle(isExpired ? '#F7C1C1' : '#EAF3DE', isExpired ? '#791F1F' : '#27500A')}>
            {dialRef || 'N/A'}
          </span>
        </div>

        <div style={tileStyle(isExpired)}>
          <div style={labelStyle(isExpired)}>Dial expiry</div>
          <span style={badgeStyle(isExpired ? '#F7C1C1' : '#FAEEDA', isExpired ? '#791F1F' : '#633806')}>
            {formatDate(dialExpiry)}
          </span>
          {isExpired && <div style={{ fontSize: '11px', color: '#A32D2D', marginTop: '5px', fontWeight: 500 }}>DIAL expired</div>}
        </div>

        <div style={{
          background: !msaOk ? '#FAEEDA' : '#f9fafb',
          border: !msaOk ? '0.5px solid #FAC775' : '0.5px solid transparent',
          borderRadius: '6px', padding: '10px 12px'
        }}>
          <div style={{ fontSize: '11px', color: !msaOk ? '#854F0B' : '#9ca3af', textTransform: 'uppercase', marginBottom: '5px' }}>MSA signed</div>
          <span style={badgeStyle(msaOk ? '#EAF3DE' : '#FAEEDA', msaOk ? '#27500A' : '#633806')}>
            {msaOk ? 'Yes' : 'Not signed'}
          </span>
        </div>

      </div>

      {isExpired && (
        <div style={{ marginTop: '10px', display: 'flex', alignItems: 'center', gap: '6px', padding: '7px 10px', background: '#FCEBEB', border: '0.5px solid #F09595', borderRadius: '6px', fontSize: '12px', color: '#791F1F', fontWeight: 500 }}>
          DIAL certification has expired — collection may not proceed until renewed.
        </div>
      )}

      {!msaOk && (
        <div style={{ marginTop: '10px', display: 'flex', alignItems: 'center', gap: '6px', padding: '7px 10px', background: '#FAEEDA', border: '0.5px solid #FAC775', borderRadius: '6px', fontSize: '12px', color: '#633806', fontWeight: 500 }}>
          MSA not signed — please ensure agreement is completed before collection.
        </div>
      )}
    </div>
  );
}

appsmith.onReady(() => {
  ReactDOM.render(<App />, document.getElementById("root"));
});
